collector_llm = ChatAnthropic(model="claude-sonnet-5")


def collector(state: DelegationState) -> dict:
    """Receives all TaskResults via operator.add; synthesises into a summary."""
    # Sort by task_id to get deterministic order regardless of completion order
    ordered = sorted(state["results"], key=lambda r: r.task_id)

    failed = [r for r in ordered if not r.success]
    if failed:
        failed_ids = ", ".join(r.task_id for r in failed)
        print(f"Warning: {len(failed)} task(s) failed: {failed_ids}")

    sections = []
    for r in ordered:
        if r.success:
            sections.append(f"### {r.assignee.title()} ({r.task_id})\n{r.output}")
        else:
            sections.append(f"### {r.assignee.title()} ({r.task_id})\n[FAILED: {r.error}]")

    combined = "\n\n".join(sections)
    prompt = f"Synthesise these specialist outputs into a unified response:\n\n{combined}"
    synthesis = collector_llm.invoke(prompt)
    return {"summary": synthesis.content}
